import json
from kafka import KafkaConsumer
from kafka.errors import NoBrokersAvailable

class FinancialTransactionProcessor:
    def __init__(self, topic):
        self.topic = topic

    def consume_messages(self):
        try:
            consumer = KafkaConsumer(bootstrap_servers=['localhost:9092'], group_id='transaction-group')
            for message in consumer:
                if message.error():
                    raise RuntimeError('Error processing transaction', message.error())
                else:
                    self._process_message(json.loads(message.value()))
        except NoBrokersAvailable:
            print("No Kafka brokers available.")
            return